import{_ as a,c as n,a as i,o as r}from"./app-E4RC_6nC.js";const d={};function c(l,e){return r(),n("div",null,e[0]||(e[0]=[i('<blockquote><p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。 欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p></blockquote><h1 id="_2026-03-23-资讯日报" tabindex="-1"><a class="header-anchor" href="#_2026-03-23-资讯日报"><span>2026-03-23 资讯日报</span></a></h1><h2 id="新闻资讯" tabindex="-1"><a class="header-anchor" href="#新闻资讯"><span>新闻资讯</span></a></h2><h3 id="马斯克启动宇宙级芯片计划terafab" tabindex="-1"><a class="header-anchor" href="#马斯克启动宇宙级芯片计划terafab"><span>马斯克启动宇宙级芯片计划Terafab</span></a></h3><p>马斯克：为发展AI、机器人和太空算力，宣布启动芯片计划Terafab，目标年产能超1太瓦，80%用于太空。虽缺时间线，但他认为太空是AI部署低成本地，此计划是关键拼图。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e912b3811f0b4789e756d0a66dd98680033d29e73e634edea7461a55d5728fb5cbfca5bb10b4&amp;idx=2&amp;mid=2247876720&amp;sn=ec64a8616ae0a70f587a254c24f57cdc#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="黄仁勋-用token给工程师当薪酬" tabindex="-1"><a class="header-anchor" href="#黄仁勋-用token给工程师当薪酬"><span>黄仁勋：用Token给工程师当薪酬</span></a></h3><p>硅谷兴起Token刷量大赛，OpenAI员工刷量惊人，风投者费用飙升。黄仁勋提议用token作薪酬，使其成第四种薪酬。不过，也有人质疑刷量竞赛的可持续性和产出质量。<a href="https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e9c783724b9e170eca4fa34b68b6687995210004ab3d63cde413d4015ae2196bd95f8ce4cd9d&amp;idx=1&amp;mid=2247876720&amp;sn=61dfbe74f822c3738aa0605c83b959dd#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="_2026北京亦庄将办万人ai大会" tabindex="-1"><a class="header-anchor" href="#_2026北京亦庄将办万人ai大会"><span>2026北京亦庄将办万人AI大会</span></a></h3><p>数字生命卡兹克：2026年4月8 - 9日在北京亦庄办AIFUT大会。曾因规模犹豫，得罗振宇鼓励、政府支持。主论坛门票收费，展区免费，会直播，选工作日是为不占大家周末。<a href="https://mp.weixin.qq.com/s?__biz=MzIyMzA5NjEyMA==&amp;chksm=f1532af4c8dd3328f740bad7648aa219a7afa8a8cc0767b50f74fd4178f952d9d7c6034ac961&amp;idx=1&amp;mid=2647680939&amp;sn=eb6d0cd640399b39908d4e89ea6cbe75#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="karpathy-ai能力无上限-一切是skill问题" tabindex="-1"><a class="header-anchor" href="#karpathy-ai能力无上限-一切是skill问题"><span>Karpathy：AI能力无上限，一切是Skill问题</span></a></h3><p>Karpathy：自己患AI精神病，工作靠智能体，能力无上限是技能问题；大量App多余，智能体将成服务对象；自动化研究潜力大，模型会物种分化；就业、开源等也有新趋势。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cfd87e7d6870d9c56096e443b72888969c82ba2dfa0ee1274faf6b5052132a21dd2dc36b1d21&amp;idx=3&amp;mid=2247525991&amp;sn=96822846a14efca28dd1d29718144d58#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="产品应用" tabindex="-1"><a class="header-anchor" href="#产品应用"><span>产品应用</span></a></h2><h3 id="openclaw-六维度变身企业可控生产力平台" tabindex="-1"><a class="header-anchor" href="#openclaw-六维度变身企业可控生产力平台"><span>OpenClaw：六维度变身企业可控生产力平台</span></a></h3><p>秋山墨客指出，企业将 OpenClaw 部署为生产力设施，要从多租户与共享、安全管控等六个维度设计。如多租户有三种模式，安全管控设四道防线，还给出成本治理等思路，助其成可控生产力平台。<a href="https://mp.weixin.qq.com/s?__biz=Mzk1NzQ1ODk5NQ==&amp;chksm=c2b8c8ee17eb25b2df4b6eb9a110f072cdad09b7785145543a49fb80e46375c90c8c8ca31f58&amp;idx=1&amp;mid=2247525467&amp;sn=38febbb03eee920ac0f079ff95818253#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="阿里让千问成生活服务生态-大脑" tabindex="-1"><a class="header-anchor" href="#阿里让千问成生活服务生态-大脑"><span>阿里让千问成生活服务生态“大脑”</span></a></h3><p>阿里前产品经理认为千问应做内部业务入口。千问上线“一句话打车”，引入时空上下文，解决现实场景需求，有望成“任务操作系统”，推动软件交互从App操作转向需求表达。<a href="https://mp.weixin.qq.com/s?__biz=MjM5ODQ2MDIyMA==&amp;chksm=bf417b4aa7d8976e06e322db6a0b8f4a906a18d563a13e1c72af316b394ef3a1bef4e639ec6a&amp;idx=1&amp;mid=2650734158&amp;sn=6af385e1378135d45399bcdb44689201#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="yolo26-sam3-搭建实用图像分割流水线" tabindex="-1"><a class="header-anchor" href="#yolo26-sam3-搭建实用图像分割流水线"><span>YOLO26+SAM3：搭建实用图像分割流水线</span></a></h3><p>datayx：用 YOLO26+SAM3 搭建实用流水线，YOLO26 定位目标，SAM3 精准分割。介绍环境配置、实战代码，该组合在检测、分割和速度上表现优，还给出优化技巧与问题解决方案。<a href="https://mp.weixin.qq.com/s?__biz=MzA4MTk3ODI2OA==&amp;chksm=869f78a3ce88fb2c31f51fe8af6f6c63b33840bb0b7d4738bb8f3a767147d428b94ceffa67f9&amp;idx=1&amp;mid=2650364660&amp;sn=b46ec5b48a8231f5fb7854a3c790de3e#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="qveris补齐龙虾量化系统数据短板" tabindex="-1"><a class="header-anchor" href="#qveris补齐龙虾量化系统数据短板"><span>QVeris补齐龙虾量化系统数据短板</span></a></h3><p>作者：龙虾量化系统受关注，但数据是短板。找到QVeris这个统一数据接口平台，经测试，它能用于金融分析等多领域，是AI时代的数据基础设施，搭配龙虾量化很实用。<a href="https://mp.weixin.qq.com/s?__biz=MzkxNjcyNTk2NA==&amp;chksm=c0fd30060611f7e58cc44445513ffda576d2fb62d44a037ecd81a257f554d1066e06c18d4ae3&amp;idx=1&amp;mid=2247491633&amp;sn=d27a9d005a172899d6c10aed98b0d82e#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="推荐文章" tabindex="-1"><a class="header-anchor" href="#推荐文章"><span>推荐文章</span></a></h2><h3 id="企业养虾-知识体系比模型更重要" tabindex="-1"><a class="header-anchor" href="#企业养虾-知识体系比模型更重要"><span>企业养虾：知识体系比模型更重要</span></a></h3><p>作者认为企业养虾和个人不同，需建知识体系，包括数据、关系等四层。飞书在提供工作环境上表现出色。企业不应只重模型，知识体系才是真正资产。<a href="https://mp.weixin.qq.com/s?__biz=Mzk1NzgxMjQ0OA==&amp;chksm=c29ba93ff4b902e57e71d7b22527d86225a6d250c342ffe7ac48e0b3f9d6f75d309a912bf0eb&amp;idx=1&amp;mid=2247494339&amp;sn=df87209e652cda5038a5a555df93e4c0#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="openai总监-ai写80-代码-提问题更重要" tabindex="-1"><a class="header-anchor" href="#openai总监-ai写80-代码-提问题更重要"><span>OpenAI总监：AI写80%代码，提问题更重要</span></a></h3><p>OpenAI Codex 技术总监 Michael Bolin 称，AI 编程时代 80%-90% 代码可由模型生成，但关键部分需人类把控。他认为提出正确问题能力比写代码更重要，长期来看编程智能体执行将更多迁移到云端。<a href="https://mp.weixin.qq.com/s?__biz=MjM5MDE0Mjc4MA==&amp;chksm=bceb5fe8914b45477a82b9928b9ba3218e8386802c97e3cc57d31fc8c79a74bf93fe8ea4d3ab&amp;idx=1&amp;mid=2651279467&amp;sn=a920c1e987ee443cb181400fc25fdb59#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="智空间-打造可复用的-ai助手工厂" tabindex="-1"><a class="header-anchor" href="#智空间-打造可复用的-ai助手工厂"><span>智空间：打造可复用的“AI助手工厂”</span></a></h3><p>智空间团队：日常工作80%任务可归为四大类，针对其挑战形成解决方案；采用分层架构，设计四套方案和prompt插拔架构；落地“助手工厂”，未来计划拓展场景、升级能力。<a href="https://mp.weixin.qq.com/s?__biz=MzIzOTU0NTQ0MA==&amp;chksm=e83f028be5d85c068d132d43b5281a66460aa8d7b05dc0029539ab8e13fbea6b1d6c0ddd7499&amp;idx=1&amp;mid=2247558977&amp;sn=dcf5e1258edd06e555cc9bff963f133a#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="开源动态" tabindex="-1"><a class="header-anchor" href="#开源动态"><span>开源动态</span></a></h2><h3 id="谷歌放出5种智能体skill设计模式" tabindex="-1"><a class="header-anchor" href="#谷歌放出5种智能体skill设计模式"><span>谷歌放出5种智能体Skill设计模式</span></a></h3><p>谷歌：研究Skill开发生态，给出5种智能体Skill设计模式，如工具封装器、生成器等，各有作用且可组合，助开发者构建更智能的Agent。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf7cb2a3c5368a60eac546f69c19b02ffb433e3b0b96b9ba545c310552e47d16ea791d929882&amp;idx=1&amp;mid=2247525991&amp;sn=c35041627adaa5fedb5376e1df132158#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="面壁智能开源edgeclaw解决openclaw痛点" tabindex="-1"><a class="header-anchor" href="#面壁智能开源edgeclaw解决openclaw痛点"><span>面壁智能开源EdgeClaw解决OpenClaw痛点</span></a></h3><p>面壁智能等联合开源EdgeClaw智能体框架。它用三级安全和性价比感知协同机制，解决OpenClaw数据泄露和成本高问题，还将持续迭代，支持更多端侧设备。<a href="https://mp.weixin.qq.com/s?__biz=MzkwMjQ0NzI0OQ==&amp;chksm=c1678e310091132a871a236ebb184e1fa9998cd64735e86d6e74e570abac08672ca32427daff&amp;idx=1&amp;mid=2247505712&amp;sn=595442d30322ecd5ba5aee9a63010080#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="asmr登场-ai终获「永久记忆」" tabindex="-1"><a class="header-anchor" href="#asmr登场-ai终获「永久记忆」"><span>ASMR登场，AI终获「永久记忆」</span></a></h3><p>Supermemory团队：超级记忆系统ASMR问世，在LongMemEval测试中达99%准确率，抛弃传统模式用多Agent并行推理。背后的Supermemory引擎能让AI有记忆，还集成多数据源，降低开发成本。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f02a829c873265c1e56eb7744f75bd9936297125ea0fe488aeb012627c460062b2248ea9eee8&amp;idx=1&amp;mid=2652685955&amp;sn=af265c58046720e4597b79c6124020f4#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="amd悬赏110万-挑战模型推理速度极限" tabindex="-1"><a class="header-anchor" href="#amd悬赏110万-挑战模型推理速度极限"><span>AMD悬赏110万，挑战模型推理速度极限</span></a></h3><p>AMD联合GPU MODE发起黑客松，悬赏110万美元，邀全球开发者挑战DeepSeek与Kimi推理速度极限。赛制分两阶段，代码要可合并，4月7日报名截止，5月19日颁奖。<a href="https://mp.weixin.qq.com/s?__biz=Mzg4NDQwNTI0OQ==&amp;chksm=ce68abab53f0a451ce0ff91c9157a3660868fc1715156ce16cecab4f570d4c48f169409c6485&amp;idx=1&amp;mid=2247589081&amp;sn=e06a58ce15c0ea992b42d6e6846fd197#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="minimax-开源技能包提升-ai-写代码质量" tabindex="-1"><a class="header-anchor" href="#minimax-开源技能包提升-ai-写代码质量"><span>MiniMax 开源技能包提升 AI 写代码质量</span></a></h3><p>MiniMax 开源 skills 仓库，让 AI 写代码质量提升。覆盖多开发场景，支持四种编程工具。在‘从 0 搭项目’场景省力，零散小功能效果不明显。<a href="https://mp.weixin.qq.com/s?__biz=MzA5MTIxNTY4MQ==&amp;chksm=860b09be9d94149ba343034d5034150fa90c1f26571eb37045ab7e8ce4e4bee7c92dcc55ce7a&amp;idx=1&amp;mid=2461159005&amp;sn=a4048da81c98407d22f1a418d6880c0f#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h2 id="算法论文" tabindex="-1"><a class="header-anchor" href="#算法论文"><span>算法论文</span></a></h2><h3 id="ai以72-准确率预言中东冲突" tabindex="-1"><a class="header-anchor" href="#ai以72-准确率预言中东冲突"><span>AI以72%准确率预言中东冲突</span></a></h3><p>阿联酋和美国研究团队：用中东冲突测试AI，它能透过表象精准预判战局，擅沿客观限制推演。经济领域表现佳，政治领域有挑战，整体预测准确率达72%。<a href="https://mp.weixin.qq.com/s?__biz=Mzg3Mzg5MjY3Nw==&amp;chksm=cf51a3597d432c9b7c7c7120179091599c0a61ee73b94da0c01e661695c55600bcc2a90aacc8&amp;idx=2&amp;mid=2247525991&amp;sn=d8f073575a50e58e4c2d2f1e2bb5373b#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="上交大-美团破code-agents打分难题" tabindex="-1"><a class="header-anchor" href="#上交大-美团破code-agents打分难题"><span>上交大&amp;美团破Code Agents打分难题</span></a></h3><p>上交大&amp;美团：现有代码智能体打分方法不佳，提出新基准PRDBench，让AI出题人审核，还训练裁判PRDJudge，提升打分准确性与稳定性，推动AI学会‘看懂需求’。<a href="https://mp.weixin.qq.com/s?__biz=Mzk0MTYzMzMxMA==&amp;chksm=c3bc03f50483303356ba506702cdb968f324262b28f5f38d4a20303a433c403fd060601288c0&amp;idx=1&amp;mid=2247505531&amp;sn=d7c3900a4612693a2d8be5fb36da5e84#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="谷歌论文-智能爆炸已至-重塑ai想象" tabindex="-1"><a class="header-anchor" href="#谷歌论文-智能爆炸已至-重塑ai想象"><span>谷歌论文：智能爆炸已至，重塑AI想象</span></a></h3><p>谷歌等研究者：真正的智能爆炸已发生，推理模型内自发涌现‘思想社会’。当下进入‘半人马时代’，AI扩展要注重制度建设，治理需构建宪政结构，别错防单体AI。<a href="https://mp.weixin.qq.com/s?__biz=MzI3MTA0MTk1MA==&amp;chksm=f084d460349fb13748f519301a3ee7820114928b61fd8ea4e0041279b3a1c07950fc47bfb42a&amp;idx=2&amp;mid=2652685955&amp;sn=346ce37a72eb952d17da926575d03305#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><h3 id="西湖大学团队-hif-vla让机器人懂时间" tabindex="-1"><a class="header-anchor" href="#西湖大学团队-hif-vla让机器人懂时间"><span>西湖大学团队：HiF-VLA让机器人懂时间</span></a></h3><p>西湖大学王东林团队：提出HiF-VLA模型，以运动信息建模时间，解决传统模型缺乏时间理解问题，提升机器人长序列任务决策能力，推动从“看到就做”到“边想边做”的转变。<a href="https://mp.weixin.qq.com/s?__biz=MzA5ODEzMjIyMA==&amp;chksm=919f9d767bf74456d3502f025d04f55ead36f4930b7f309bf4601c4323a16a07f951d90ddb27&amp;idx=2&amp;mid=2247732500&amp;sn=8f5733949df7b9b051323f4ced5e6b23#rd" target="_blank" rel="noopener noreferrer">&gt;阅读原文</a></p><p style="text-align:center;"><img id="weixin_qr" src="https://meikan-public-images.oss-cn-beijing.aliyuncs.com/imeikan/assets/2025-05-18234303-hub.png" style="max-width:800px;object-fit:cover;"></p><p><a href="https://aireadinghub.com/" target="_blank" rel="noopener noreferrer">官网：www.AiReadingHub.com</a></p>',49)]))}const s=a(d,[["render",c]]),t=JSON.parse('{"path":"/posts/2026-03-23.html","title":"AI日报：马斯克启动宇宙级芯片计划Terafab; 黄仁勋：用Token给工程师当薪酬; 2026北京亦庄将办万人AI大会","lang":"zh-CN","frontmatter":{"date":"2026-03-23T00:00:00.000Z","title":"AI日报：马斯克启动宇宙级芯片计划Terafab; 黄仁勋：用Token给工程师当薪酬; 2026北京亦庄将办万人AI大会"},"headers":[{"level":2,"title":"新闻资讯","slug":"新闻资讯","link":"#新闻资讯","children":[{"level":3,"title":"马斯克启动宇宙级芯片计划Terafab","slug":"马斯克启动宇宙级芯片计划terafab","link":"#马斯克启动宇宙级芯片计划terafab","children":[]},{"level":3,"title":"黄仁勋：用Token给工程师当薪酬","slug":"黄仁勋-用token给工程师当薪酬","link":"#黄仁勋-用token给工程师当薪酬","children":[]},{"level":3,"title":"2026北京亦庄将办万人AI大会","slug":"_2026北京亦庄将办万人ai大会","link":"#_2026北京亦庄将办万人ai大会","children":[]},{"level":3,"title":"Karpathy：AI能力无上限，一切是Skill问题","slug":"karpathy-ai能力无上限-一切是skill问题","link":"#karpathy-ai能力无上限-一切是skill问题","children":[]}]},{"level":2,"title":"产品应用","slug":"产品应用","link":"#产品应用","children":[{"level":3,"title":"OpenClaw：六维度变身企业可控生产力平台","slug":"openclaw-六维度变身企业可控生产力平台","link":"#openclaw-六维度变身企业可控生产力平台","children":[]},{"level":3,"title":"阿里让千问成生活服务生态“大脑”","slug":"阿里让千问成生活服务生态-大脑","link":"#阿里让千问成生活服务生态-大脑","children":[]},{"level":3,"title":"YOLO26+SAM3：搭建实用图像分割流水线","slug":"yolo26-sam3-搭建实用图像分割流水线","link":"#yolo26-sam3-搭建实用图像分割流水线","children":[]},{"level":3,"title":"QVeris补齐龙虾量化系统数据短板","slug":"qveris补齐龙虾量化系统数据短板","link":"#qveris补齐龙虾量化系统数据短板","children":[]}]},{"level":2,"title":"推荐文章","slug":"推荐文章","link":"#推荐文章","children":[{"level":3,"title":"企业养虾：知识体系比模型更重要","slug":"企业养虾-知识体系比模型更重要","link":"#企业养虾-知识体系比模型更重要","children":[]},{"level":3,"title":"OpenAI总监：AI写80%代码，提问题更重要","slug":"openai总监-ai写80-代码-提问题更重要","link":"#openai总监-ai写80-代码-提问题更重要","children":[]},{"level":3,"title":"智空间：打造可复用的“AI助手工厂”","slug":"智空间-打造可复用的-ai助手工厂","link":"#智空间-打造可复用的-ai助手工厂","children":[]}]},{"level":2,"title":"开源动态","slug":"开源动态","link":"#开源动态","children":[{"level":3,"title":"谷歌放出5种智能体Skill设计模式","slug":"谷歌放出5种智能体skill设计模式","link":"#谷歌放出5种智能体skill设计模式","children":[]},{"level":3,"title":"面壁智能开源EdgeClaw解决OpenClaw痛点","slug":"面壁智能开源edgeclaw解决openclaw痛点","link":"#面壁智能开源edgeclaw解决openclaw痛点","children":[]},{"level":3,"title":"ASMR登场，AI终获「永久记忆」","slug":"asmr登场-ai终获「永久记忆」","link":"#asmr登场-ai终获「永久记忆」","children":[]},{"level":3,"title":"AMD悬赏110万，挑战模型推理速度极限","slug":"amd悬赏110万-挑战模型推理速度极限","link":"#amd悬赏110万-挑战模型推理速度极限","children":[]},{"level":3,"title":"MiniMax 开源技能包提升 AI 写代码质量","slug":"minimax-开源技能包提升-ai-写代码质量","link":"#minimax-开源技能包提升-ai-写代码质量","children":[]}]},{"level":2,"title":"算法论文","slug":"算法论文","link":"#算法论文","children":[{"level":3,"title":"AI以72%准确率预言中东冲突","slug":"ai以72-准确率预言中东冲突","link":"#ai以72-准确率预言中东冲突","children":[]},{"level":3,"title":"上交大&美团破Code Agents打分难题","slug":"上交大-美团破code-agents打分难题","link":"#上交大-美团破code-agents打分难题","children":[]},{"level":3,"title":"谷歌论文：智能爆炸已至，重塑AI想象","slug":"谷歌论文-智能爆炸已至-重塑ai想象","link":"#谷歌论文-智能爆炸已至-重塑ai想象","children":[]},{"level":3,"title":"西湖大学团队：HiF-VLA让机器人懂时间","slug":"西湖大学团队-hif-vla让机器人懂时间","link":"#西湖大学团队-hif-vla让机器人懂时间","children":[]}]}],"git":{"updatedTime":1777179853000,"contributors":[{"name":"GitHub Actions","username":"","email":"actions@github.com","commits":1}],"changelog":[{"hash":"cde2b8100b1a6e6e235c39a2ec01d8028bda2d7c","time":1777179853000,"email":"actions@github.com","author":"GitHub Actions","message":"Auto-commit generated files on 2026-04-26T05:04:13.825Z"}]},"filePathRelative":"posts/2026-03-23.md","excerpt":"<blockquote>\\n<p>All in AI，看见未来。 每天精选最值得读的AI文章，帮你筛掉时代的噪音。 以简讯见广度，以深读见洞察。 技术、趋势、思考，一站式掌握AI世界。\\n欢迎关注公众号「AI Reading Hub」，获取更多AI资讯和技术文章。</p>\\n</blockquote>\\n<h1>2026-03-23 资讯日报</h1>\\n<h2>新闻资讯</h2>\\n<h3>马斯克启动宇宙级芯片计划Terafab</h3>\\n<p>马斯克：为发展AI、机器人和太空算力，宣布启动芯片计划Terafab，目标年产能超1太瓦，80%用于太空。虽缺时间线，但他认为太空是AI部署低成本地，此计划是关键拼图。<a href=\\"https://mp.weixin.qq.com/s?__biz=MzIzNjc1NzUzMw==&amp;chksm=e912b3811f0b4789e756d0a66dd98680033d29e73e634edea7461a55d5728fb5cbfca5bb10b4&amp;idx=2&amp;mid=2247876720&amp;sn=ec64a8616ae0a70f587a254c24f57cdc#rd\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">&gt;阅读原文</a></p>"}');export{s as comp,t as data};
